messages.content:
Use `Effect.tap` — it runs a side-effecting effect, ignores its result, and threads the original value through.

```ts
import { Effect, Console } from "effect";

declare const loadUser: (id: string) => Effect.Effect<{ id: string; name: string }>;

export const loadUserTraced = (id: string) =>
  loadUser(id).pipe(
    Effect.tap((u) => Console.log(`loaded user ${u.id}`)),
  );
// vs Effect.flatMap which would replace the value with the log effect's result.
```

Insert `Effect.tap` between the two steps — logging returns its own effect, but `tap` discards it and keeps the `ChargeReceipt` flowing into `persistOrder`.

```ts
import { Effect } from "effect";

interface Order { readonly id: string; readonly cents: number }
interface ChargeReceipt { readonly txId: string; readonly cents: number }
interface Persisted { readonly orderId: string; readonly txId: string }

declare const chargeCard: (o: Order) => Effect.Effect<ChargeReceipt>;
declare const persistOrder: (r: ChargeReceipt) => Effect.Effect<Persisted>;

export const placeOrder = (o: Order): Effect.Effect<Persisted> =>
  chargeCard(o).pipe(
    Effect.tap((r) => Effect.logInfo(`charged ${r.cents}c as ${r.txId}`)),
    Effect.flatMap(persistOrder),
  );
```

```ts
import { Effect, Console } from "effect";

declare const fetchJson: <T>(url: string) => Effect.Effect<T>;

export const getAndPeek = <T>(url: string): Effect.Effect<T> =>
  fetchJson<T>(url).pipe(
    Effect.tap((body) => Console.log("payload bytes:", JSON.stringify(body).length)),
  );
```

`Effect.tap` is the effectful analogue of a "passthrough log" — the return channel is still `Effect<T>`.

`Effect.tapError` taps the failure channel — if the effect succeeds, it's a no-op; if it fails, the handler runs and the original error propagates.

```ts
import { Effect, Data } from "effect";

class FetchError extends Data.TaggedError("FetchError")<{ readonly url: string; readonly cause: string }> {}

declare const fetchUrl: (url: string) => Effect.Effect<string, FetchError>;

export const fetchWithErrorLog = (url: string): Effect.Effect<string, FetchError> =>
  fetchUrl(url).pipe(
    Effect.tapError((e) => Effect.logError(`fetch ${e.url} failed: ${e.cause}`)),
  );
```

`Effect.tapBoth` takes a single `{ onSuccess, onFailure }` object, so you declare both side-effects in one place. It's equivalent to composing `tap` and `tapError`, but keeps the two handlers visually co-located — useful for matched instrumentation pairs like "request:start/request:end" metrics.

```ts
import { Effect, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly status: number }> {}

declare const sendRequest: (url: string) => Effect.Effect<{ status: number; body: string }, HttpError>;

export const instrumentedSend = (url: string): Effect.Effect<{ status: number; body: string }, HttpError> =>
  sendRequest(url).pipe(
    Effect.tapBoth({
      onSuccess: (res) => Effect.logInfo(`ok ${res.status} ${url}`),
      onFailure: (e) => Effect.logWarning(`fail ${e.status} ${url}`),
    }),
  );
```

```ts
import { Effect, Ref } from "effect";

interface Counters {
  readonly ok: Ref.Ref<number>;
  readonly err: Ref.Ref<number>;
}

export const withMetrics =
  <A, E, R>(counters: Counters) =>
  (eff: Effect.Effect<A, E, R>): Effect.Effect<A, E, R> =>
    eff.pipe(
      Effect.tap(() => Ref.update(counters.ok, (n) => n + 1)),
      Effect.tapError(() => Ref.update(counters.err, (n) => n + 1)),
    );

declare const fetchProfile: (id: string) => Effect.Effect<{ name: string }, Error>;

export const instrumented = (counters: Counters, id: string) =>
  fetchProfile(id).pipe(withMetrics(counters));
```

The `<A, E, R>` generics preserve the full effect signature, so `withMetrics` can wrap any effect without changing its type.

```ts
import { Effect, Clock } from "effect";

interface Row { readonly [k: string]: unknown }
declare const runSql: (sql: string) => Effect.Effect<ReadonlyArray<Row>>;
declare const recordLatency: (ms: number) => Effect.Effect<void>;

export const queryDb = (sql: string): Effect.Effect<ReadonlyArray<Row>> =>
  Effect.gen(function* () {
    const start = yield* Clock.currentTimeMillis;
    return yield* runSql(sql).pipe(
      Effect.tap(() =>
        Effect.gen(function* () {
          const end = yield* Clock.currentTimeMillis;
          yield* recordLatency(end - start);
        }),
      ),
    );
  });
```

The `tap` reads the clock again and emits the delta — the SQL result passes through untouched.

`Effect.as(log, u)` is a workaround for "run the log, keep `u`". `Effect.tap` expresses that directly.

```ts
import { Effect, Console } from "effect";

interface User { readonly id: string; readonly name: string }
declare const fetchUser: (id: string) => Effect.Effect<User>;

export const fetchUserLogged = (id: string): Effect.Effect<User> =>
  fetchUser(id).pipe(
    Effect.tap((u) => Console.log(u.name)),
  );
```

```ts
import { Effect, Option } from "effect";

interface Cache<A> {
  readonly get: (k: string) => Effect.Effect<Option.Option<A>>;
  readonly put: (k: string, v: A) => Effect.Effect<void>;
}

export const cachedLookup =
  <A>(cache: Cache<A>, source: (k: string) => Effect.Effect<A>) =>
  (key: string): Effect.Effect<A> =>
    Effect.gen(function* () {
      const hit = yield* cache.get(key);
      if (Option.isSome(hit)) return hit.value;
      return yield* source(key).pipe(
        Effect.tap(() => Effect.logDebug(`cache miss: ${key}`)),
        Effect.tap((v) => cache.put(key, v)),
      );
    });
```

Two taps: one for the trace log, one to populate the cache — both return the computed value unchanged.

```ts
import { Effect } from "effect";

interface Order { readonly id: string; readonly version: number }
interface Patch { readonly op: string }

declare const applyPatch: (o: Order, patch: Patch) => Effect.Effect<Order>;
declare const writeAudit: (entry: { orderId: string; op: string; version: number }) => Effect.Effect<void>;

export const updateOrder = (o: Order, patch: Patch): Effect.Effect<Order> =>
  applyPatch(o, patch).pipe(
    Effect.tap((next) =>
      writeAudit({ orderId: next.id, op: patch.op, version: next.version }),
    ),
  );
```

Put `Effect.tapError` inside the retried effect — the schedule re-runs the whole `pipe`, so each failure goes through the tap before the retry decision.

```ts
import { Effect, Schedule, Duration, Data } from "effect";

class RpcError extends Data.TaggedError("RpcError")<{ readonly code: number }> {}

declare const callRpc: () => Effect.Effect<string, RpcError>;

export const callWithLoggedRetries: Effect.Effect<string, RpcError> = callRpc().pipe(
  Effect.tapError((e) => Effect.logWarning(`rpc failed, code=${e.code}, retrying`)),
  Effect.retry(Schedule.compose(Schedule.exponential(Duration.millis(100)), Schedule.recurs(3))),
);
```

```ts
import { Effect } from "effect";

export const traced =
  <A, E, R>(label: string, eff: Effect.Effect<A, E, R>): Effect.Effect<A, E, R> =>
    Effect.gen(function* () {
      yield* Effect.logInfo(`${label}: start`);
      return yield* eff.pipe(
        Effect.tapBoth({
          onSuccess: () => Effect.logInfo(`${label}: ok`),
          onFailure: (e) =>
            Effect.logError(`${label}: fail ${String(e)}`),
        }),
      );
    });

declare const loadFile: (p: string) => Effect.Effect<string, Error>;

export const loadConfig = traced("config", loadFile("/etc/app.json"));
```

```ts
import { Effect, Console } from "effect";

interface User { readonly id: string; readonly email: string }
declare const loadUser: (id: string) => Effect.Effect<User>;

export const loadUserLogged = (id: string): Effect.Effect<User> =>
