`tap` runs the log effect and automatically returns `u`, so no manual scoping is required.

```ts
import { Effect, Data } from "effect";

class SmtpError extends Data.TaggedError("SmtpError")<{ readonly code: string }> {}

interface Message { readonly to: string; readonly body: string }
interface Receipt { readonly messageId: string }

declare const sendEmail: (m: Message) => Effect.Effect<Receipt, SmtpError>;
declare const incSent: () => Effect.Effect<void>;
declare const incFailed: () => Effect.Effect<void>;

export const sendTracked = (m: Message): Effect.Effect<Receipt, SmtpError> =>
