```ts
import { Effect } from "effect";

interface Request { readonly id: string; readonly path: string }
interface Response { readonly status: number; readonly body: string }

declare const handle: (req: Request) => Effect.Effect<Response>;

export const handleTraced = (req: Request): Effect.Effect<Response> =>
  handle(req).pipe(
    Effect.tap((res) =>
      Effect.logInfo(`[req=${req.id}] ${req.path} -> ${res.status}`),
    ),
  );
```

Closing over `req.id` inside the tap keeps the correlation id in scope without threading it through the return type.

```ts
import { Effect, Data } from "effect";

class BadBody extends Data.TaggedError("BadBody")<{ readonly msg: string }> {}
class Unauthenticated extends Data.TaggedError("Unauthenticated")<{}> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly need: string }> {}
class HandlerError extends Data.TaggedError("HandlerError")<{ readonly cause: string }> {}

interface Req { readonly headers: Readonly<Record<string, string>>; readonly rawBody: string }
interface Body { readonly action: string }
interface Principal { readonly userId: string; readonly scopes: ReadonlyArray<string> }
interface Result { readonly ok: true; readonly data: unknown }
interface Res { readonly status: number; readonly body: string }

declare const parseBody: (raw: string) => Effect.Effect<Body, BadBody>;
declare const authenticate: (h: Readonly<Record<string, string>>) => Effect.Effect<Principal, Unauthenticated>;
declare const authorize: (p: Principal, action: string) => Effect.Effect<void, Forbidden>;
declare const runHandler: (p: Principal, b: Body) => Effect.Effect<Result, HandlerError>;

export const handleRequest = (
  req: Req,
): Effect.Effect<Res, BadBody | Unauthenticated | Forbidden | HandlerError> =>
  Effect.gen(function* () {
    const body = yield* parseBody(req.rawBody);
    const principal = yield* authenticate(req.headers);
    yield* authorize(principal, body.action);
    const out = yield* runHandler(principal, body);
    return { status: 200, body: JSON.stringify(out) } satisfies Res;
  });
```

```ts
import { Effect, Data, Exit } from "effect";

class BeginError extends Data.TaggedError("BeginError")<{}> {}
class CommitError extends Data.TaggedError("CommitError")<{}> {}
class RollbackError extends Data.TaggedError("RollbackError")<{}> {}

interface Tx { readonly id: string }

declare const beginTx: () => Effect.Effect<Tx, BeginError>;
declare const commitTx: (t: Tx) => Effect.Effect<void, CommitError>;
declare const rollbackTx: (t: Tx) => Effect.Effect<void, RollbackError>;

export const withTransaction =
  <A, E>(body: (tx: Tx) => Effect.Effect<A, E>): Effect.Effect<A, E | BeginError | CommitError> =>
    Effect.gen(function* () {
      const tx = yield* beginTx();
      const result = yield* Effect.exit(body(tx));
      if (Exit.isSuccess(result)) {
        yield* commitTx(tx);
        return result.value;
      }
      yield* Effect.orDie(rollbackTx(tx));
      return yield* Effect.failCause(result.cause);
    });
```

The `Exit` inspection lets us branch on success vs failure while preserving the original error in the E channel.

```ts
import { Effect, Data, Ref, Clock } from "effect";

class RefreshError extends Data.TaggedError("RefreshError")<{ readonly cause: string }> {}

interface Token { readonly value: string; readonly expiresAtMs: number }

declare const refresh: () => Effect.Effect<Token, RefreshError>;

export const makeTokenSource = (initial: Token) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<Token>(initial);
    const getValid = (): Effect.Effect<Token, RefreshError> =>
      Effect.gen(function* () {
        const now = yield* Clock.currentTimeMillis;
        const cur = yield* Ref.get(ref);
        if (cur.expiresAtMs > now + 30_000) return cur;
        const fresh = yield* refresh();
        yield* Ref.set(ref, fresh);
        return fresh;
      });
    return { getValid } as const;
  });
```

The 30-second skew prevents races where a token expires between "check" and "use".

```ts
import { Effect, Queue, Data } from "effect";

class DecodeError extends Data.TaggedError("DecodeError")<{ readonly raw: string }> {}
class DispatchError extends Data.TaggedError("DispatchError")<{ readonly topic: string }> {}

interface Envelope { readonly topic: string; readonly rawBody: string; readonly ackId: string }
interface Event { readonly topic: string; readonly payload: unknown }

declare const decode: (raw: string) => Effect.Effect<Event, DecodeError>;
declare const dispatch: (e: Event) => Effect.Effect<void, DispatchError>;
declare const ack: (id: string) => Effect.Effect<void>;

export const runSubscriber = (
  inbox: Queue.Dequeue<Envelope>,
): Effect.Effect<never, DecodeError | DispatchError> =>
  Effect.gen(function* () {
    while (true) {
      const env = yield* Queue.take(inbox);
      const event = yield* decode(env.rawBody);
      yield* dispatch(event);
      yield* ack(env.ackId);
    }
  });
```

The `while (true)` inside `Effect.gen` never resolves naturally — its return type is `Effect<never, E>`, signalling a long-running service.

```ts
import { Effect, Ref, Data } from "effect";

class CircuitOpen extends Data.TaggedError("CircuitOpen")<{ readonly failures: number }> {}

interface State { readonly failures: number; readonly openUntilMs: number }

export const makeBreaker = (threshold: number) =>
  Effect.gen(function* () {
    const state = yield* Ref.make<State>({ failures: 0, openUntilMs: 0 });
    const run = <A, E>(eff: Effect.Effect<A, E>): Effect.Effect<A, E | CircuitOpen> =>
      Effect.gen(function* () {
        const s = yield* Ref.get(state);
        if (s.failures >= threshold) {
          return yield* Effect.fail(new CircuitOpen({ failures: s.failures }));
        }
        return yield* eff.pipe(
          Effect.tap(() => Ref.set(state, { failures: 0, openUntilMs: 0 })),
          Effect.tapError(() =>
            Ref.update(state, (p) => ({ ...p, failures: p.failures + 1 })),
          ),
        );
      });
    return { run } as const;
  });
```

```ts
import { Effect, Option, Ref, HashMap } from "effect";

export const makeMemoCache = <K, V>() =>
  Effect.gen(function* () {
    const store = yield* Ref.make<HashMap.HashMap<K, V>>(HashMap.empty());
    const get = (key: K, load: (k: K) => Effect.Effect<V>): Effect.Effect<V> =>
      Effect.gen(function* () {
        const map = yield* Ref.get(store);
        const hit = HashMap.get(map, key);
        if (Option.isSome(hit)) return hit.value;
        const v = yield* load(key);
        yield* Ref.update(store, (m) => HashMap.set(m, key, v));
        return v;
      });
    return { get } as const;
  });
```

`HashMap` and `Ref` are both from `"effect"` in v3 — no imports from `@effect/*` v2 paths.

```ts
import { Effect, Data } from "effect";

class NotFound extends Data.TaggedError("NotFound")<{ readonly id: string }> {}

interface Params { readonly id: string }
interface Resource { readonly id: string; readonly name: string }
interface HttpResponse { readonly status: number; readonly json: unknown }

declare const loadResource: (id: string) => Effect.Effect<Resource, NotFound>;

export const getResourceHandler = (params: Params): Effect.Effect<HttpResponse> =>
  Effect.gen(function* () {
    const r = yield* loadResource(params.id).pipe(
      Effect.catchTag("NotFound", () => Effect.succeed(null as Resource | null)),
    );
    if (r === null) return { status: 404, json: { error: "not_found" } };
    return { status: 200, json: r };
  });
```

The handler's success channel is `HttpResponse` unconditionally — the error is translated to a 404 body inside `catchTag`.

```ts
import { Effect } from "effect";

export const makeLimiter = (maxConcurrent: number) =>
  Effect.gen(function* () {
    const sem = yield* Effect.makeSemaphore(maxConcurrent);
    const run = <A, E, R>(eff: Effect.Effect<A, E, R>): Effect.Effect<A, E, R> =>
      sem.withPermits(1)(eff);
    return { run } as const;
  });

declare const callApi: (url: string) => Effect.Effect<string>;

export const bounded = (urls: ReadonlyArray<string>) =>
  Effect.gen(function* () {
    const limiter = yield* makeLimiter(4);
    return yield* Effect.all(urls.map((u) => limiter.run(callApi(u))), {
      concurrency: "unbounded",
    });
  });
```

```ts
import { Effect, Data } from "effect";

class PageError extends Data.TaggedError("PageError")<{ readonly cursor: string | null }> {}

interface Page {
  readonly items: ReadonlyArray<unknown>;
  readonly nextCursor: string | null;
}

declare const fetchPage: (cursor: string | null) => Effect.Effect<Page, PageError>;

export const crawlAll: Effect.Effect<ReadonlyArray<unknown>, PageError> =
  Effect.gen(function* () {
    const acc: unknown[] = [];
    let cursor: string | null = null;
    for (;;) {
      const page: Page = yield* fetchPage(cursor);
      acc.push(...page.items);
      if (page.nextCursor === null) return acc;
      cursor = page.nextCursor;
    }
  });
```

Mutation of `acc` is local to the generator — callers only see the returned `ReadonlyArray`.

```ts
import { Effect, Data, Exit } from "effect";

class Degraded extends Data.TaggedError("Degraded")<{ readonly failed: ReadonlyArray<string> }> {}

interface Probe {
  readonly name: string;
  readonly critical: boolean;
  readonly run: Effect.Effect<void>;
}

export const runHealth = (
  probes: ReadonlyArray<Probe>,
): Effect.Effect<{ ok: ReadonlyArray<string>; failed: ReadonlyArray<string> }, Degraded> =>
  Effect.gen(function* () {
    const ok: string[] = [];
    const failed: string[] = [];
    const criticalFailed: string[] = [];
    for (const p of probes) {
      const exit = yield* Effect.exit(p.run);
      if (Exit.isSuccess(exit)) ok.push(p.name);
      else {
        failed.push(p.name);
        if (p.critical) criticalFailed.push(p.name);
      }
    }
    if (criticalFailed.length > 0) {
      return yield* Effect.fail(new Degraded({ failed: criticalFailed }));
    }
    return { ok, failed };
  });
```

```ts
import { Effect, Queue, Ref, Data } from "effect";

class JobError extends Data.TaggedError("JobError")<{ readonly jobId: string; readonly cause: string }> {}

interface Job { readonly id: string; readonly payload: unknown }
interface Stats { readonly ok: number; readonly failed: number }

declare const processJob: (j: Job) => Effect.Effect<void, JobError>;

export const runWorker = (
  inbox: Queue.Dequeue<Job>,
  stats: Ref.Ref<Stats>,
): Effect.Effect<never> =>
  Effect.gen(function* () {
    while (true) {
      const job = yield* Queue.take(inbox);
      const res = yield* Effect.either(processJob(job));
      if (res._tag === "Right") {
        yield* Ref.update(stats, (s) => ({ ...s, ok: s.ok + 1 }));
      } else {
        yield* Effect.logError(`job ${res.left.jobId} failed: ${res.left.cause}`);
        yield* Ref.update(stats, (s) => ({ ...s, failed: s.failed + 1 }));
      }
    }
  });
```

`Effect.either` lifts the failure channel into `Either<E, A>` so the loop never aborts on a single bad job.

```ts
import { Effect, Data } from "effect";

class BadSignature extends Data.TaggedError("BadSignature")<{}> {}
class BadPayload extends Data.TaggedError("BadPayload")<{ readonly msg: string }> {}
class UnknownSubscription extends Data.TaggedError("UnknownSubscription")<{ readonly id: string }> {}
class DispatchError extends Data.TaggedError("DispatchError")<{ readonly cause: string }> {}

interface RawHook { readonly signature: string; readonly body: string; readonly subId: string }
interface Payload { readonly event: string }
interface Subscription { readonly id: string; readonly url: string }

declare const verifySig: (h: RawHook) => Effect.Effect<void, BadSignature>;
declare const parsePayload: (raw: string) => Effect.Effect<Payload, BadPayload>;
declare const findSub: (id: string) => Effect.Effect<Subscription, UnknownSubscription>;
declare const dispatch: (s: Subscription, p: Payload) => Effect.Effect<void, DispatchError>;

export const receiveHook = (
  h: RawHook,
): Effect.Effect<void, BadSignature | BadPayload | UnknownSubscription | DispatchError> =>
  Effect.gen(function* () {
    yield* verifySig(h);
    const payload = yield* parsePayload(h.body);
    const sub = yield* findSub(h.subId);
    yield* dispatch(sub, payload);
  });
```

```ts
import { Effect, Data } from "effect";

class DlqError extends Data.TaggedError("DlqError")<{ readonly reason: string }> {}

export const withDlq =
  <A, E>(dlq: (err: E) => Effect.Effect<void, DlqError>) =>
  (eff: Effect.Effect<A, E>): Effect.Effect<A, E | DlqError> =>
    Effect.gen(function* () {
      const out = yield* Effect.either(eff);
      if (out._tag === "Right") return out.right;
      yield* dlq(out.left);
      return yield* Effect.fail(out.left);
    });

declare const saveRecord: (r: unknown) => Effect.Effect<void, Error>;
declare const publishDead: (e: Error) => Effect.Effect<void, DlqError>;

export const trySave = (r: unknown) => saveRecord(r).pipe(withDlq(publishDead));
```

The DLQ publish happens before re-failing, so observability is preserved without swallowing the error.

```ts
import { Effect, Data } from "effect";

class BadMime extends Data.TaggedError("BadMime")<{ readonly mime: string }> {}
class UploadError extends Data.TaggedError("UploadError")<{ readonly cause: string }> {}
class MetaError extends Data.TaggedError("MetaError")<{ readonly cause: string }> {}

interface FileBlob { readonly bytes: Uint8Array; readonly mime: string; readonly filename: string }
interface UploadResult { readonly sha256: string; readonly location: string; readonly filename: string }

declare const validateMime: (mime: string) => Effect.Effect<void, BadMime>;
declare const sha256: (b: Uint8Array) => Effect.Effect<string>;
declare const putBlob: (key: string, b: Uint8Array) => Effect.Effect<string, UploadError>;
declare const writeMeta: (u: UploadResult) => Effect.Effect<void, MetaError>;

export const uploadFile = (
  f: FileBlob,
): Effect.Effect<UploadResult, BadMime | UploadError | MetaError> =>
  Effect.gen(function* () {
    yield* validateMime(f.mime);
    const digest = yield* sha256(f.bytes);
    const loc = yield* putBlob(digest, f.bytes);
    const result: UploadResult = { sha256: digest, location: loc, filename: f.filename };
    yield* writeMeta(result);
    return result;
  });
```

```ts
import { Effect, Data, Exit } from "effect";

class LockBusy extends Data.TaggedError("LockBusy")<{ readonly key: string }> {}
class LockReleaseError extends Data.TaggedError("LockReleaseError")<{ readonly key: string }> {}

interface LockHandle { readonly token: string }

declare const tryAcquire: (key: string) => Effect.Effect<LockHandle, LockBusy>;
declare const release: (key: string, token: string) => Effect.Effect<void, LockReleaseError>;

export const withLock =
  <A, E>(key: string, body: Effect.Effect<A, E>): Effect.Effect<A, E | LockBusy | LockReleaseError> =>
    Effect.gen(function* () {
      const handle = yield* tryAcquire(key);
      const result = yield* Effect.exit(body);
      yield* release(key, handle.token);
      if (Exit.isFailure(result)) return yield* Effect.failCause(result.cause);
      return result.value;
    });
```

The release always runs — even on body failure — before the error is re-raised.

```ts
import { Effect, Queue, Ref, Data } from "effect";

class FlushError extends Data.TaggedError("FlushError")<{ readonly count: number; readonly cause: string }> {}

interface Record { readonly id: string; readonly data: unknown }

declare const bulkInsert: (rows: ReadonlyArray<Record>) => Effect.Effect<void, FlushError>;

export const runBatcher = (
  inbox: Queue.Dequeue<Record>,
  batchSize: number,
): Effect.Effect<never, FlushError> =>
  Effect.gen(function* () {
    const buf = yield* Ref.make<ReadonlyArray<Record>>([]);
    while (true) {
      const next = yield* Queue.take(inbox);
      const flushed = yield* Ref.modify(buf, (prev) => {
        const upd = [...prev, next];
        return upd.length >= batchSize ? [upd, [] as ReadonlyArray<Record>] : [[] as ReadonlyArray<Record>, upd];
      });
      if (flushed.length > 0) yield* bulkInsert(flushed);
    }
  });
```

`Ref.modify` atomically swaps the buffer so two concurrent takes can't reissue the same batch.

```ts
import { Effect, Ref } from "effect";

interface Handler { readonly name: string; readonly run: Effect.Effect<void> }

export const makeShutdown = () =>
  Effect.gen(function* () {
    const handlers = yield* Ref.make<ReadonlyArray<Handler>>([]);
    const register = (h: Handler) => Ref.update(handlers, (hs) => [...hs, h]);
    const drain: Effect.Effect<void> = Effect.gen(function* () {
      const list = yield* Ref.get(handlers);
      for (const h of list) {
        const result = yield* Effect.either(h.run);
        if (result._tag === "Left") {
          yield* Effect.logError(`shutdown ${h.name} failed: ${String(result.left)}`);
        } else {
          yield* Effect.logInfo(`shutdown ${h.name} ok`);
        }
      }
    });
    return { register, drain } as const;
  });
```

```ts
import { Effect, Data } from "effect";

class ReadError extends Data.TaggedError("ReadError")<{}> {}
class PublishError extends Data.TaggedError("PublishError")<{ readonly id: string }> {}
class MarkError extends Data.TaggedError("MarkError")<{ readonly id: string }> {}

interface OutboxRow { readonly id: string; readonly topic: string; readonly payload: unknown }

declare const readPending: () => Effect.Effect<ReadonlyArray<OutboxRow>, ReadError>;
declare const publish: (r: OutboxRow) => Effect.Effect<void, PublishError>;
declare const markSent: (id: string) => Effect.Effect<void, MarkError>;

export const drainOutbox: Effect.Effect<number, ReadError | PublishError | MarkError> =
  Effect.gen(function* () {
    const rows = yield* readPending();
    let sent = 0;
    for (const row of rows) {
      yield* publish(row);
      yield* markSent(row.id);
      sent += 1;
    }
    return sent;
  });
```

If `publish` succeeds but `markSent` fails, the overall effect fails — the next drain retries the row, which is why publishers must be idempotent.

```ts
import { Effect, Exit } from "effect";

interface SagaStep<E> {
  readonly name: string;
  readonly action: Effect.Effect<void, E>;
  readonly compensate: Effect.Effect<void>;
}

export const runSaga = <E>(
  steps: ReadonlyArray<SagaStep<E>>,
): Effect.Effect<void, E> =>
  Effect.gen(function* () {
    const done: SagaStep<E>[] = [];
    const exit = yield* Effect.exit(
      Effect.gen(function* () {
        for (const step of steps) {
          yield* step.action;
          done.push(step);
        }
      }),
    );
    if (Exit.isSuccess(exit)) return;
    for (const s of done.reverse()) {
      yield* Effect.orDie(s.compensate);
    }
    return yield* Effect.failCause(exit.cause);
  });
```

The inner `Effect.exit` isolates partial progress; compensations run on the reversed `done` list.

```ts
import { Effect, Data, HashMap } from "effect";

class UnknownCommand extends Data.TaggedError("UnknownCommand")<{ readonly type: string }> {}
class HandlerError extends Data.TaggedError("HandlerError")<{ readonly type: string; readonly cause: string }> {}

interface Command { readonly type: string; readonly payload: unknown }

type Handler = (payload: unknown) => Effect.Effect<unknown, HandlerError>;

export const dispatch = (
  handlers: HashMap.HashMap<string, Handler>,
  cmd: Command,
): Effect.Effect<unknown, UnknownCommand | HandlerError> =>
  Effect.gen(function* () {
    const maybe = HashMap.get(handlers, cmd.type);
    if (maybe._tag === "None") {
      return yield* Effect.fail(new UnknownCommand({ type: cmd.type }));
    }
    return yield* maybe.value(cmd.payload);
  });
```

The two tagged errors let callers distinguish "no handler wired" from "handler ran and failed" without string matching.

