import { Effect, Data } from "effect";

class SchemaError extends Data.TaggedError("SchemaError")<{ readonly path: string }> {}
class QuotaExceeded extends Data.TaggedError("QuotaExceeded")<{ readonly userId: string }> {}
class PersistError extends Data.TaggedError("PersistError")<{ readonly cause: string }> {}

