import { Effect, Queue, Data } from "effect";

class WriteError extends Data.TaggedError("WriteError")<{ readonly cause: string }> {}

interface ServerEvent { readonly id: string; readonly kind: string; readonly data: string }

interface Writer {
  readonly write: (chunk: string) => Effect.Effect<void, WriteError>;
}

const format = (e: ServerEvent): string =>
  `id: ${e.id}\nevent: ${e.kind}\ndata: ${e.data}\n\n`;

export const runSse = (
  source: Queue.Dequeue<ServerEvent>,
  writer: Writer,
): Effect.Effect<never, WriteError> =>
  Effect.gen(function* () {
    while (true) {
      const ev = yield* Queue.take(source);
      yield* writer.write(format(ev));
    }
  });
```

Pure `format` stays outside the generator — keep side-effect boundaries visible in `yield*` lines.

```ts
import { Effect, Ref, Clock, Duration } from "effect";

interface Bucket { readonly tokens: number; readonly lastRefillMs: number }

export const makeTokenBucket = (capacity: number, refillPerSec: number) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<Bucket>({ tokens: capacity, lastRefillMs: 0 });
    const acquire = (): Effect.Effect<void> =>
      Effect.gen(function* () {
        while (true) {
          const now = yield* Clock.currentTimeMillis;
          const got = yield* Ref.modify(ref, (b) => {
            const add = Math.floor(((now - b.lastRefillMs) / 1000) * refillPerSec);
            const tokens = Math.min(capacity, b.tokens + Math.max(0, add));
            if (tokens <= 0) return [false, { tokens, lastRefillMs: now }];
            return [true, { tokens: tokens - 1, lastRefillMs: now }];
          });
          if (got) return;
          yield* Effect.sleep(Duration.millis(50));
        }
      });
    return { acquire } as const;
  });
```

`Effect.tap` receives the success value, runs a side-effect (log, metric, trace span), and yields the original value forward. Because the tap's own return is discarded, stacking multiple taps keeps the pipeline's type fixed at `Effect<A, E, R>` no matter how much observability you layer on.

```ts
import { Effect, Console } from "effect";

interface Order { readonly id: string; readonly total: number }
interface Charged extends Order { readonly txId: string }

declare const authorize: (o: Order) => Effect.Effect<Order>;
declare const capture: (o: Order) => Effect.Effect<Charged>;
declare const incCounter: (name: string) => Effect.Effect<void>;
declare const emitSpan: (name: string, attrs: Record<string, unknown>) => Effect.Effect<void>;

export const chargeOrder = (o: Order): Effect.Effect<Charged> =>
  authorize(o).pipe(
    Effect.tap((auth) => Console.log(`authorized ${auth.id}`)),
    Effect.flatMap(capture),
    Effect.tap((c) => incCounter("orders.captured")),
    Effect.tap((c) => emitSpan("order.charged", { id: c.id, tx: c.txId })),
  );
```

The return type is `Effect<Charged>` whether we add zero taps or ten.
